// ─── Email Transport ──────────────────────────────────────────────────────────
let transporter;

const initTransporter = () => {
    if (process.env.SMTP_HOST && process.env.SMTP_USER && process.env.SMTP_PASS) {
        transporter = nodemailer.createTransport({
            host: process.env.SMTP_HOST,
            port: parseInt(process.env.SMTP_PORT || '587'),
            secure: process.env.SMTP_PORT === '465',
            auth: { user: process.env.SMTP_USER, pass: process.env.SMTP_PASS }
        });
        console.log('[Notification] SMTP transporter configured (live)');
    } else {
        nodemailer.createTestAccount((err, account) => {
            if (err) { console.error('Ethereal setup failed:', err.message); return; }
            transporter = nodemailer.createTransport({
                host: account.smtp.host,
                port: account.smtp.port,
                secure: account.smtp.secure,
                auth: { user: account.user, pass: account.pass }
            });
            console.log('[Notification] Ethereal test email configured (no SMTP env vars)');
        });
    }
};
initTransporter();

// ─── Twilio SMS ───────────────────────────────────────────────────────────────
let twilioClient = null;
const TWILIO_FROM = process.env.TWILIO_PHONE_NUMBER;
if (process.env.TWILIO_ACCOUNT_SID && process.env.TWILIO_AUTH_TOKEN) {
    const twilio = require('twilio');
    twilioClient = twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);
    console.log('[Notification] Twilio SMS client initialized (live)');
} else {
    console.log('[Notification] Twilio not configured — SMS will be console-logged (mock)');
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
async function sendEmail(to, subject, html) {
    if (!to) return null;
    if (!transporter) throw new Error('Mail transporter not ready yet');
    const info = await transporter.sendMail({ from: FROM_EMAIL, to, subject, html });
    const preview = nodemailer.getTestMessageUrl(info);
    if (preview) console.log(`[Notification] Email preview: ${preview}`);
    return { messageId: info.messageId, previewUrl: preview || null };
}

async function sendSms(to, body) {
    if (!to) return null;
    if (!twilioClient) {
        console.log(`[Notification] Mock SMS → ${to}: ${body}`);
        return { mock: true };
    }
    const msg = await twilioClient.messages.create({ from: TWILIO_FROM, to, body });
    return { sid: msg.sid };
}

async function getPatient(id) {
    try { return (await axios.get(`${PATIENT_SERVICE_URL}/profile/${id}`, { timeout: 5000 })).data; }
    catch { return null; }
}

async function getDoctor(id) {
    try { return (await axios.get(`${DOCTOR_SERVICE_URL}/profile/${id}`, { timeout: 5000 })).data; }
    catch { return null; }
}

