// Called by appointment-service after a new booking
app.post('/appointment-booking', async (req, res) => {
    const { patientId, doctorId, date, time } = req.body;
    if (!patientId || !doctorId) return res.status(400).json({ error: 'patientId and doctorId required' });

    const [patient, doctor] = await Promise.all([getPatient(patientId), getDoctor(doctorId)]);
    const patientName = patient?.name || 'Patient';
    const doctorName  = doctor?.name  || 'Doctor';
    const results = { emails: [], sms: [] };
    const errors  = [];

    try {
        if (patient?.email) results.emails.push(await sendEmail(patient.email, 'Appointment Booked — SmartHealth Care', bookingHtml(patientName, patientName, doctorName, date, time)));
        if (doctor?.email)  results.emails.push(await sendEmail(doctor.email,  'New Appointment Request — SmartHealth Care', bookingHtml(`Dr. ${doctorName}`, patientName, doctorName, date, time)));
    } catch (e) { errors.push({ type: 'email', error: e.message }); }

    try {
        const sms = `SmartHealth: Appointment on ${date} at ${time}. Patient: ${patientName}, Dr. ${doctorName}.`;
        if (patient?.contactNumber) results.sms.push(await sendSms(patient.contactNumber, sms));
        if (doctor?.phone)          results.sms.push(await sendSms(doctor.phone, `SmartHealth: New appointment from ${patientName} on ${date} at ${time}.`));
    } catch (e) { errors.push({ type: 'sms', error: e.message }); }

    // Persist notification records
    try {
        await NotificationLog.insertMany([
            { type: 'booking', recipientRole: 'patient', recipientId: patientId, recipientName: patientName, title: 'Appointment Booked', message: `Appointment with Dr. ${doctorName} on ${date} at ${time}`, patientId, doctorId },
            { type: 'booking', recipientRole: 'doctor', recipientId: doctorId, recipientName: `Dr. ${doctorName}`, title: 'New Appointment Request', message: `New appointment from ${patientName} on ${date} at ${time}`, patientId, doctorId }
        ]);
    } catch (e) { console.error('[Notification] DB save error:', e.message); }

    res.json({ message: 'Booking notifications dispatched', results, errors });
});

// Called by appointment-service on status change (accepted/rejected/cancelled/completed)
app.post('/appointment-status', async (req, res) => {
    const { patientId, doctorId, date, time, status } = req.body;
    if (!patientId || !doctorId || !status) return res.status(400).json({ error: 'patientId, doctorId, status required' });

    const [patient, doctor] = await Promise.all([getPatient(patientId), getDoctor(doctorId)]);
    const patientName = patient?.name || 'Patient';
    const doctorName  = doctor?.name  || 'Doctor';
    const results = { emails: [], sms: [] };
    const errors  = [];

    try {
        if (patient?.email) results.emails.push(await sendEmail(patient.email, `Appointment ${status} — SmartHealth Care`, statusHtml(patientName, status, patientName, doctorName, date, time)));
        // Notify doctor on cancellation
        if (status === 'cancelled' && doctor?.email) results.emails.push(await sendEmail(doctor.email, 'Appointment Cancelled — SmartHealth Care', statusHtml(`Dr. ${doctorName}`, status, patientName, doctorName, date, time)));
    } catch (e) { errors.push({ type: 'email', error: e.message }); }

    try {
        const sms = `SmartHealth: Your appointment on ${date} at ${time} has been ${status}.`;
        if (patient?.contactNumber) results.sms.push(await sendSms(patient.contactNumber, sms));
        if (status === 'cancelled' && doctor?.phone) results.sms.push(await sendSms(doctor.phone, `SmartHealth: Appointment with ${patientName} on ${date} was cancelled.`));
    } catch (e) { errors.push({ type: 'sms', error: e.message }); }

    // Persist notification records
    const records = [
        { type: 'status', recipientRole: 'patient', recipientId: patientId, recipientName: patientName, title: `Appointment ${status.charAt(0).toUpperCase() + status.slice(1)}`, message: `Your appointment on ${date} at ${time} has been ${status}`, patientId, doctorId }
    ];
    if (status === 'cancelled' || status === 'accepted' || status === 'rejected') {
        records.push({ type: 'status', recipientRole: 'doctor', recipientId: doctorId, recipientName: `Dr. ${doctorName}`, title: `Appointment ${status.charAt(0).toUpperCase() + status.slice(1)}`, message: `Appointment with ${patientName} on ${date} has been ${status}`, patientId, doctorId });
    }
    try { await NotificationLog.insertMany(records); } catch (e) { console.error('[Notification] DB save error:', e.message); }

    res.json({ message: `Status (${status}) notifications dispatched`, results, errors });
});

