// Generic endpoints (kept for direct use or testing)
app.post('/send-email', async (req, res) => {
    const { to, subject, text, html } = req.body;
    if (!transporter) return res.status(503).json({ error: 'Mail server not initialized yet' });
    try {
        const result = await sendEmail(to, subject, html || `<p>${text}</p>`);
        res.json({ message: 'Email sent', ...result });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

app.post('/send-sms', async (req, res) => {
    const { to, text } = req.body;
    try {
        const result = await sendSms(to, text);
        res.json({ message: 'SMS dispatched', ...(result || {}) });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

// ─── Notification History ─────────────────────────────────────────────────────
app.get('/history/patient/:patientId', async (req, res) => {
    try {
        const logs = await NotificationLog.find({ recipientId: req.params.patientId, recipientRole: 'patient' }).sort({ createdAt: -1 }).limit(50);
        res.json(logs);
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.get('/history/doctor/:doctorId', async (req, res) => {
    try {
        const logs = await NotificationLog.find({ recipientId: req.params.doctorId, recipientRole: 'doctor' }).sort({ createdAt: -1 }).limit(50);
        res.json(logs);
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.delete('/history/patient/:patientId/:notificationId', async (req, res) => {
    try {
        const { patientId, notificationId } = req.params;
        const deleted = await NotificationLog.findOneAndDelete({ _id: notificationId, recipientId: patientId, recipientRole: 'patient' });
        if (!deleted) return res.status(404).json({ error: 'Notification not found' });
        res.json({ message: 'Notification deleted' });
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.delete('/history/doctor/:doctorId/:notificationId', async (req, res) => {
    try {
        const { doctorId, notificationId } = req.params;
        const deleted = await NotificationLog.findOneAndDelete({ _id: notificationId, recipientId: doctorId, recipientRole: 'doctor' });
        if (!deleted) return res.status(404).json({ error: 'Notification not found' });
        res.json({ message: 'Notification deleted' });
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.delete('/history/patient/:patientId', async (req, res) => {
    try {
        const result = await NotificationLog.deleteMany({ recipientId: req.params.patientId, recipientRole: 'patient' });
        res.json({ message: 'Patient notifications cleared', deletedCount: result.deletedCount });
    } catch (err) { res.status(500).json({ error: err.message }); }
});

